# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

import pyqrcode
from pyotp import TOTP
import qrcode
import base64
import uuid
import time
import hashlib
import hmac

class TOTPSecret:
    def __init__(self):
        self.secrets = {}

    def generate_secret(self, user_id):
        secret_key = str(uuid.uuid4())
        self.secrets[user_id] = secret_key
        return secret_key

    def create_qr_code(self, secret_key, user_id):
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(f"otpauth://totp/{user_id}?secret={base64.b32encode(secret_key.encode()).decode()}")
        qr.make(fit=True)
        img = qr.make_image()
        return img

    def validate_totp(self, secret_key, user_id, code):
        totp = TOTP(secret_key)
        expected_code = totp.now()
        hash_value = hmac.new(secret_key.encode(), str(int(time.time())).encode(), hashlib.sha1).digest()[:6]
        expected_code = int.from_bytes(hash_value, 'big')
        return expected_code == code

def main():
    secret_generator = TOTPSecret()

    user_id = input("Enter User ID: ")
    if user_id not in secret_generator.secrets:
        secret_key = secret_generator.generate_secret(user_id)
        print(f"Generated Secret Key for {user_id}: {secret_key}")
        
        qr_code_img = secret_generator.create_qr_code(secret_key, user_id)
        qr_code_img.save('totp_qr.png')

    code = input("Enter TOTP Code: ")
    
    if secret_generator.validate_totp(secret_generator.secrets[user_id], user_id, int(code)):
        print(f"TOTP Code is Valid for {user_id}")
    else:
        print(f"Invalid TOTP Code for {user_id}")

if __name__ == "__main__":
    main()